import{_ as a,o as t,c as n,ae as r}from"./chunks/framework.B6gjLfeO.js";const c=JSON.parse('{"title":"Leanplum Configuration","description":"","frontmatter":{"title":"Leanplum Configuration","slug":"leanplum-configuration"},"headers":[],"relativePath":"developer-hub/leanplum-configuration.md","filePath":"developer-hub/leanplum-configuration.md"}'),o={name:"developer-hub/leanplum-configuration.md"};function i(l,e,s,h,p,d){return t(),n("div",null,[...e[0]||(e[0]=[r('<p><em>[Image: 1328]</em></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Leanplum is the mobile marketing platform that drives app engagement &amp; ROI.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><p>Once the Branch SDK is integrated into an app, Branch can detect which Branch Links are leading to installs, re-opens, and users&#39; actions. Enabling this integration and providing your relevant Ids will result in Branch automatically forwarding referred events to Leanplum, in the exact format Leanplum expects.</p><h3 id="branch-events-sent-to-leanplum" tabindex="-1">Branch Events Sent to Leanplum <a class="header-anchor" href="#branch-events-sent-to-leanplum" aria-label="Permalink to &quot;Branch Events Sent to Leanplum&quot;">​</a></h3><p>The events Branch sends to third party data tools varies based on the events the partner supports as well as whether or not you&#39;ve implemented the Branch SDK to measure said events.</p><p>Leanplum supports the following events:</p><ul><li>Install<br> *Reinstall</li></ul><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable Leanplum, you need to have completed the following:</p><ol><li><p>Admin access to your <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Have the Advanced Data Feeds add-on enabled on your Branch account. Advanced Data Feeds can be included as an add-on to both the Engagement and Performance <a href="./packaging.html">products</a>.</p></li><li><p>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><a href="./track-branch-events.html">Track events</a></li></ul></li><li><p><a href="https://docs.leanplum.com/reference" target="_blank" rel="noreferrer">Implement the Leanplum SDK</a></p></li><li><p>Admin access to your Leanplum account.</p></li></ol><h2 id="enable-leanplum" tabindex="-1">Enable Leanplum <a class="header-anchor" href="#enable-leanplum" aria-label="Permalink to &quot;Enable Leanplum&quot;">​</a></h2><h2 id="_1-retrieve-ids-from-leanplum" tabindex="-1">1. Retrieve IDs from Leanplum <a class="header-anchor" href="#_1-retrieve-ids-from-leanplum" aria-label="Permalink to &quot;1. Retrieve IDs from Leanplum&quot;">​</a></h2><p>Before you can enable the integration in your Branch dashboard, you need to retrieve your credentials from your Leanplum account.</p><p>Branch requires these credentials to not only authenticate, but to ensure your Branch data is being sent to the correct account.</p><p>Branch requires the following credentials from your Leanplum account:</p><ul><li><strong>App ID</strong> - This is the ID applied to your application in Leanplum that tells us which dashboard the data is applied to.This key is used in your Leanplum integration.</li><li><strong>Production Key</strong> - This key is used to tell Leanplum to send the data to the production/live pipeline. It is specific to your app and Leanplum dashboard. See our available production methods.</li></ul><p>Please see <a href="https://docs.leanplum.com/docs/how-to-integrate-external-attribution-services" target="_blank" rel="noreferrer">Leanplum&#39;s documentation</a> on how to find these values.</p><h2 id="_2-connect-leanplum-in-branch" tabindex="-1">2. Connect Leanplum in Branch <a class="header-anchor" href="#_2-connect-leanplum-in-branch" aria-label="Permalink to &quot;2. Connect Leanplum in Branch&quot;">​</a></h2><p>In the Branch Dashboard in Data Feeds → <a href="https://dashboard.branch.io/data-feeds/integrations" target="_blank" rel="noreferrer"><strong>Data Integrations</strong> tab</a>, find and search for Leanplum.</p><p>Enter the App ID and Production Key from the previous step, then hit <strong>Enable</strong>.</p><h2 id="_3-verify-data-sent" tabindex="-1">3. Verify Data Sent <a class="header-anchor" href="#_3-verify-data-sent" aria-label="Permalink to &quot;3. Verify Data Sent&quot;">​</a></h2><p>Once the above steps are complete, you are now ready to start launching campaigns. Branch-attributed conversions will be sent to Airship. To verify data is being sent from Branch to Airship, you can look at the Branch Dashboard&#39;s <a href="https://dashboard.branch.io/liveview/webhooks" target="_blank" rel="noreferrer">Liveview Webhook Records</a> and apply the following filter:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Operator</th><th>Value</th></tr></thead><tbody><tr><td>webhook partner key</td><td>equals</td><td>di_leanplum</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Wait Period</p><p>Please be patient as data may take some time to flow through Branch&#39;s attribution systems and onto Leanplum. If data has not appeared in Leanplum after 30 minutes of completing a test conversion, review the above steps to see if you may have missed something.</p></div>',26)])])}const m=a(o,[["render",i]]);export{c as __pageData,m as default};
